// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}




function getWeatherIconName(condition: string): string {
  if (!condition) return 'sun';
  const lower = condition.toLowerCase();
  if (lower.includes('rain') || lower.includes('drizzle') || lower.includes('shower')) return 'cloud-rain';
  if (lower.includes('snow') || lower.includes('ice') || lower.includes('flurries')) return 'snowflake';
  if (lower.includes('storm') || lower.includes('thunder') || lower.includes('lightning')) return 'cloud-lightning';
  if (lower.includes('cloud') || lower.includes('overcast')) return 'cloud';
  if (lower.includes('fog') || lower.includes('mist')) return 'cloud-fog';
  if (lower.includes('wind') || lower.includes('breeze')) return 'wind';
  if (lower.includes('clear') || lower.includes('sun')) return 'sun';
  return 'sun';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2}>{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                {props.condition}
              </Text>
            </Stack>
            <Icon name={getWeatherIconName(props.condition)} size={48} color="var(--ggui-color-primary-500)" />
          </Stack>

          <Stack direction="horizontal" justify="between" align="end">
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
              {props.temperature}°{props.unit}
            </Text>
            <Stack gap="var(--ggui-spacing-2)" align="end">
              <Box background="var(--ggui-color-surfaceVariant)" paddingX="var(--ggui-spacing-3)" paddingY="var(--ggui-spacing-1)" borderRadius="var(--ggui-shape-radius-full)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={14} color="var(--ggui-color-onSurfaceVariant)" />
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">Humidity: {props.humidity}%</Text>
                </Stack>
              </Box>
              <Box background="var(--ggui-color-surfaceVariant)" paddingX="var(--ggui-spacing-3)" paddingY="var(--ggui-spacing-1)" borderRadius="var(--ggui-shape-radius-full)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={14} color="var(--ggui-color-onSurfaceVariant)" />
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">Wind: {props.windSpeed} {props.unit === 'F' ? 'mph' : 'km/h'}</Text>
                </Stack>
              </Box>
            </Stack>
          </Stack>

          <Divider margin="var(--ggui-spacing-4)" />

          <Stack gap="var(--ggui-spacing-4)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">5-Day Forecast</Text>
            <Stack direction="horizontal" justify="between" align="center" wrap>
              {props.forecast && props.forecast.map((day, idx) => (
                <Stack key={idx} align="center" gap="var(--ggui-spacing-2)">
                  <Text variant="bodySmall" weight="medium">{day.day}</Text>
                  <Icon name={getWeatherIconName(day.icon || '')} size={24} color="var(--ggui-color-primary-500)" />
                  <Stack direction="horizontal" gap="var(--ggui-spacing-1)">
                    <Text variant="bodySmall" weight="bold">{day.high}°</Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{day.low}°</Text>
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
